using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: EF Core 9 renamed "Discriminator" to "$type".
        // Existing documents still use "Discriminator", so we must preserve it.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 2: EF Core 9 changed the id format from "EntityType|Key" to just "Key".
        // Existing documents use "Blog|1" format, so we must opt back in.
        modelBuilder.Entity<Blog>().HasIdProperty(b => b.Id, useDiscriminatorInId: true);

        // Breaking change 3: Cosmos DB does not support indexes defined via EF Core.
        // EF Core 9 now throws instead of silently ignoring. Removed HasIndex call.
        // Indexes must be configured via the Azure Portal or Cosmos DB SDK.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

